import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import { BrowserRouter as Router, Route, Routes } from 'react-router-dom';
import HomePage from './screens/homePage';
import EmpresasPage from './screens/empresasPage';
import ContactoPage from './screens/contactoPage';
import HistoriaPage from './screens/historiaPage';
import EditorEmpresasPage from './screens/editorEmpresasPage';
import EditorUsuariosPage from './screens/editorUsuariosPage';
import Navbar from './components/Navbar';
import NuevaEmpresa from './screens/nuevaEmpresaPage';
import TipoSocietario from './screens/tipoSocietarioPage';
import PropietariosYTipoSocietario from './screens/propietariosYTipoSocietarioPage';


ReactDOM.render(
  <Router>
    <Navbar />
    <Routes>
      <Route path="/" element={<HomePage />} />
      <Route path="/empresas" element={<EmpresasPage />} />
      <Route path="/contacto" element={<ContactoPage />} />
      <Route path="/historia" element={<HistoriaPage />} />
      <Route path="/editor-empresas" element={<EditorEmpresasPage />} />
      <Route path="/editor-usuarios" element={<EditorUsuariosPage />} />
      <Route path="/editor-empresa/nueva" element={<NuevaEmpresa />} />
      <Route path="/editor-empresa/societario" element={<TipoSocietario />} />
      <Route path="/editor-empresa/propietarios" element={<PropietariosYTipoSocietario />} />

    </Routes>
  </Router>,
  document.getElementById('root')
);
